 11	import InfoCircleIcon from '@patternfly/react-icons/dist/esm/icons/info-circle-icon';
 12	import IncidentsDetailsRowTable from './IncidentsDetailsRowTable';
 13	import { BellIcon, BellSlashIcon, SearchIcon } from '@patternfly/react-icons';
 14	import { useSelector } from 'react-redux';
 15	import * as _ from 'lodash-es';
 16	
 17	export const IncidentsTable = ({ namespace }) => {
 18	  const columnNames = {
 19	    checkbox: '',
 20	    component: 'Component',
 21	    severity: 'Severity',
 22	    state: 'State',
 23	  };
 24	  const [expandedAlerts, setExpandedAlerts] = React.useState([]);
 25	  const setAlertExpanded = (alert, isExpanding = true) =>
 26	    setExpandedAlerts((prevExpanded) => {
 27	      const otherAlertExpanded = prevExpanded.filter((r) => r !== alert.component);
 28	      return isExpanding ? [...otherAlertExpanded, alert.component] : otherAlertExpanded;
 29	    });
 30	  const isAlertExpanded = (alert) => expandedAlerts.includes(alert.component);
 31	  const alertsTableData = useSelector((state) =>
 32	    state.plugins.mcp.getIn(['incidentsData', 'alertsTableData']),
 33	  );
 34	  const alertsAreLoading = useSelector((state) =>
 35	    state.plugins.mcp.getIn(['incidentsData', 'alertsAreLoading']),
 36	  );
 37	
 38	  return (
 39	    <Card>
 40	      <CardBody>
 41	        <Table aria-label="alerts-table" isExpandable>
 42	          <Thead>
 43	            <Tr>
 44	              <Th screenReaderText="Row expansion" />
 45	              <Th width={50}>{columnNames.component}</Th>
 46	              <Th width={25}>{columnNames.severity}</Th>
 47	              <Th width={25}>{columnNames.state}</Th>
 48	            </Tr>
 49	          </Thead>
 50	          {_.isEmpty(alertsTableData) || alertsAreLoading ? (
 51	            <Tr>
 52	              <Td colSpan={4}>
 53	                <EmptyState
 54	                  icon={SearchIcon}
 55	                  style={{
 56	                    height: '150px',
 57	                  }}
 58	                >
 59	                  <EmptyStateBody>
 60	                    <Bullseye>No incidents selected.</Bullseye>
 61	                  </EmptyStateBody>
 62	                </EmptyState>
 63	              </Td>
 64	            </Tr>
 65	          ) : (
 66	            alertsTableData.map((alert, rowIndex) => {
 67	              return (
 68	                <Tbody key={rowIndex} isExpanded={isAlertExpanded(alert)}>
 69	                  <Tr>
 70	                    <Td
 71	                      expand={
 72	                        alert.alertsExpandedRowData
 73	                          ? {
 74	                              rowIndex,
 75	                              isExpanded: isAlertExpanded(alert),
 76	                              onToggle: () => setAlertExpanded(alert, !isAlertExpanded(alert)),
 77	                              expandId: 'alert-expandable',
 78	                            }
 79	                          : undefined
 80	                      }
 81	                    />
 82	                    <Td dataLabel={columnNames.component}>{alert.component}</Td>
 83	                    <Td>
 84	                      {alert.critical > 0 ? (
 85	                        <Label color="red" icon={<InfoCircleIcon />}>
 86	                          {alert.critical}
 87	                        </Label>
 88	                      ) : (
 89	                        ''
 90	                      )}
 91	                      {alert.warning > 0 ? (
 92	                        <Label color="gold" icon={<InfoCircleIcon />}>
 93	                          {alert.warning}
 94	                        </Label>
 95	                      ) : (
 96	                        ''
 97	                      )}
 98	                      {alert.info > 0 ? (
 99	                        <Label color="blue" icon={<InfoCircleIcon />}>
100	                          {alert.info}
101	                        </Label>
102	                      ) : (
103	                        ''
104	                      )}
105	                    </Td>
106	                    <Td dataLabel={columnNames.state}>
107	                      {alert.alertstate === 'resolved' ? (
108	                        <BellSlashIcon className="text-muted" />
109	                      ) : (
110	                        <BellIcon />
111	                      )}
112	                    </Td>
113	                  </Tr>
114	                  {alert.alertsExpandedRowData && (
115	                    <Tr isExpanded={isAlertExpanded(alert)}>
116	                      <Td width={100} colSpan={6}>
117	                        <ExpandableRowContent>
118	                          <IncidentsDetailsRowTable
119	                            alerts={alert.alertsExpandedRowData}
120	                            namespace={namespace}
121	                          />
122	                        </ExpandableRowContent>
123	                      </Td>
124	                    </Tr>
125	                  )}
126	                </Tbody>
127	              );
128	            })
129	          )}
130	        </Table>
131	      </CardBody>
132	    </Card>
133	  );
134	};

