 25	      const otherAlertExpanded = prevExpanded.filter((r) => r !== alert.component);
 26	      return isExpanding ? [...otherAlertExpanded, alert.component] : otherAlertExpanded;
 27	    });
 28	  const isAlertExpanded = (alert) => expandedAlerts.includes(alert.component);
